class Solution:
    def trap(self, height):
        if not height: return 0
        l, r = 0, len(height) - 1
        lm, rm, w = 0, 0, 0
        while l < r:
            if height[l] < height[r]:
                if height[l] >= lm: lm = height[l]
                else: w += lm - height[l]
                l += 1
            else:
                if height[r] >= rm: rm = height[r]
                else: w += rm - height[r]
                r -= 1
        return w

